import React from 'react';

const Experience = () => (
  <section
    id="Experience"
    className="min-h-screen flex flex-col items-center py-24"
    style={{ background: '#112240', fontFamily: "'Orbitron', sans-serif" }}
  >
    <h1 className="text-4xl text-white mb-12 font-bold">Experience</h1>

    <div className="max-w-2xl w-full">
      <div
        className="p-6 rounded-xl"
        style={{ background: '#f8f9fa', borderLeft: '5px solid #0d6efd' }}
      >
        <h3 style={{ color: '#0b1f3a' }}>Freelance Developer</h3>
        <p style={{ color: '#555' }}>2024–Present</p>
      </div>
    </div>
  </section>
);

export default Experience;
